# ============================================================
# FUNÇÕES UTILITÁRIAS
# ============================================================

def safe_slug(text: str) -> str:
    replacements = {
        "á": "a", "à": "a", "ã": "a", "â": "a",
        "é": "e", "ê": "e",
        "í": "i",
        "ó": "o", "ô": "o", "õ": "o",
        "ú": "u",
        "ç": "c",
        "Á": "A", "À": "A", "Ã": "A", "Â": "A",
        "É": "E", "Ê": "E",
        "Í": "I",
        "Ó": "O", "Ô": "O", "Õ": "O",
        "Ú": "U",
        "Ç": "C",
    }
    out = "".join(replacements.get(ch, ch) for ch in text)
    out = out.lower().replace(" ", "_").replace("—", "-").replace("/", "_")
    return "".join(ch for ch in out if ch.isalnum() or ch in "_-")


def estimate_time_minutes(exercises: List[Dict[str, object]]) -> int:
    total_sec = 8 * 60  # aquecimento
    transition_sec = 35
    for ex in exercises:
        series = int(ex["series"])
        descanso_txt = str(ex["descanso"])
        if "120" in descanso_txt:
            rest = 105
        elif "90" in descanso_txt:
            rest = 85
        elif "75" in descanso_txt:
            rest = 70
        else:
            rest = 55
        execution = 42
        total_sec += series * execution + max(series - 1, 1) * rest + transition_sec
    return round(total_sec / 60)


def get_volume_table(plan_dict: Dict[str, List[Dict[str, object]]]) -> pd.DataFrame:
    rows = []
    for treino, exercises in plan_dict.items():
        for ex in exercises:
            rows.append({
                "Treino": treino,
                "Grupo": ex["grupo"],
                "Séries": ex["series"],
            })
    df = pd.DataFrame(rows)
    if df.empty:
        return df
    return (
        df.groupby("Grupo", as_index=False)["Séries"]
        .sum()
        .rename(columns={"Séries": "Séries semanais planejadas"})
        .sort_values("Séries semanais planejadas", ascending=False)
    )


def init_state() -> None:
    if "acesso_liberado" not in st.session_state:
        st.session_state.acesso_liberado = False
    if "historico" not in st.session_state:
        st.session_state.historico = []


def render_access_screen() -> None:
    st.markdown(
        f"""
        <div class="access-container">
            <img class="access-logo" src="data:image/jpeg;base64,{LOGO_B64}" alt="Alê e Aninha Treinos">
            <div class="access-question">{FRASE_ACESSO}</div>
            <div class="access-subtitle">Ficha fixa, carga registrada e evolução controlada.</div>
        </div>
        """,
        unsafe_allow_html=True,
    )

    col_a, col_b, col_c = st.columns([1, 2, 1])
    with col_b:
        if st.button("Entrar no treino", type="primary", use_container_width=True):
            st.session_state.acesso_liberado = True
            st.rerun()
    st.stop()


def create_csv_download(df: pd.DataFrame) -> bytes:
    buffer = StringIO()
    df.to_csv(buffer, index=False, sep=";")
    return buffer.getvalue().encode("utf-8-sig")


